import React, { useState, useEffect } from 'react';
import { collection, getDocs, updateDoc, doc, deleteDoc, getDoc } from 'firebase/firestore';
import { db } from './firebase';
import ProductService from './ProductService';
import { useNavigate } from 'react-router-dom';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [pricePerDay, setPricePerDay] = useState('');
  const [mainImageFile, setMainImageFile] = useState(null);
  const [additionalImageFiles, setAdditionalImageFiles] = useState([]);
  const [category, setCategory] = useState('Clothing');
  const [subcategory, setSubcategory] = useState('Men\'s Clothing');
  const [users, setUsers] = useState([]);
  const [supplierRequests, setSupplierRequests] = useState([]);
  const [showProductForm, setShowProductForm] = useState(false);
  const [showUserList, setShowUserList] = useState(false);
  const [showSupplierRequests, setShowSupplierRequests] = useState(false);
  const [totalEarnings, setTotalEarnings] = useState(0);
  const [checkoutEarnings, setCheckoutEarnings] = useState([]);
  const [totalCheckoutEarnings, setTotalCheckoutEarnings] = useState(0);
  const [feedbacks, setFeedbacks] = useState([]);
  const [products, setProducts] = useState([]);
  const [showProductHistory, setShowProductHistory] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchUsers();
    fetchOrders();
    fetchCheckoutEarnings();
    fetchFeedbacks();
  }, []);

  const fetchFeedbacks = async () => {
    try {
      const feedbackCollection = collection(db, 'feedback');
      const querySnapshot = await getDocs(feedbackCollection);
      const feedbackList = querySnapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
      setFeedbacks(feedbackList);
    } catch (error) {
      console.error('Error fetching feedbacks:', error);
    }
  };

  const fetchUsers = async () => {
    try {
      const usersCollection = collection(db, 'users');
      const querySnapshot = await getDocs(usersCollection);
      const usersList = querySnapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
      setUsers(usersList);

      const requests = usersList
        .filter((user) => user.supplierRequest)
        .map((user) => ({
          id: user.id,
          userName: user.name,
          userEmail: user.email,
          idProofUrl: user.supplierRequest.idFileUrl,
        }));
      setSupplierRequests(requests);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchOrders = async () => {
    try {
      const ordersCollection = collection(db, 'orders');
      const querySnapshot = await getDocs(ordersCollection);
      const ordersList = querySnapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));

      const total = ordersList.reduce((acc, order) => acc + (order.serviceFee || 0), 0);
      setTotalEarnings(total);
    } catch (error) {
      console.error('Error fetching orders:', error);
    }
  };

  const fetchCheckoutEarnings = async () => {
    try {
      const checkoutCollection = collection(db, 'checkout');
      const querySnapshot = await getDocs(checkoutCollection);

      const checkoutList = querySnapshot.docs.map((doc) => ({
        id: doc.id,
        serviceFee: doc.data().serviceFee || 0,
        finalTotal: doc.data().finalTotal || 0,
        userId: doc.data().userId || 'Unknown',
        productNames: doc.data().productNames || [],
      }));

      const total = checkoutList.reduce((acc, order) => acc + (order.serviceFee || 0), 0);
      setTotalCheckoutEarnings(total);

      const earningsByCheckout = checkoutList.map((order) => ({
        id: order.id,
        totalEarnings: order.serviceFee,
        finalTotal: order.finalTotal,
        userId: order.userId,
        productNames: order.productNames.join(', '),
      }));
      setCheckoutEarnings(earningsByCheckout);
    } catch (error) {
      console.error('Error fetching checkout earnings:', error);
    }
  };

  const handleAdditionalImagesChange = (e) => {
    setAdditionalImageFiles(e.target.files);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newProduct = {
      name,
      description,
      pricePerDay: parseInt(pricePerDay, 10),
      category,
      subcategory,
    };

    try {
      await ProductService.addProduct(newProduct, mainImageFile, additionalImageFiles);
      setName('');
      setDescription('');
      setPricePerDay('');
      setMainImageFile(null);
      setAdditionalImageFiles([]);
      setShowProductForm(false);
    } catch (error) {
      console.error('Error adding product:', error);
    }
  };

  const handleDeleteUser = async (userId) => {
    try {
      const user = users.find((user) => user.id === userId);
      if (user.role === 'admin') {
        alert('Cannot delete an admin user.');
        return;
      }
      await deleteDoc(doc(db, 'users', userId));
      setUsers(users.filter((user) => user.id !== userId));
      setSupplierRequests(supplierRequests.filter((request) => request.id !== userId));
    } catch (error) {
      console.error('Error deleting user:', error);
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    try {
      const userDocRef = doc(db, 'users', userId);
      const userDoc = await getDoc(userDocRef);
      const userData = userDoc.data();

      if (userData.role === 'admin') {
        alert('The admin role cannot be changed.');
        return;
      }

      await updateDoc(userDocRef, {
        isSupplier: newRole === 'Supplier',
      });
      fetchUsers();
    } catch (error) {
      console.error('Error updating user role:', error);
    }
  };

  const handleApproveSupplier = async (userId) => {
    try {
      const userDocRef = doc(db, 'users', userId);
      await updateDoc(userDocRef, {
        isSupplier: true,
        supplierRequest: null,
      });
      setSupplierRequests(supplierRequests.filter((request) => request.id !== userId));
    } catch (error) {
      console.error('Error approving supplier request:', error);
    }
  };

  const handleDenySupplier = async (userId) => {
    try {
      const userDocRef = doc(db, 'users', userId);
      await updateDoc(userDocRef, {
        supplierRequest: null,
      });
      setSupplierRequests(supplierRequests.filter((request) => request.id !== userId));
    } catch (error) {
      console.error('Error denying supplier request:', error);
    }
  };

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const productsSnapshot = await ProductService.getAllProducts();
        if (!productsSnapshot.empty) {
          const productList = productsSnapshot.docs.map((doc) => ({
            id: doc.id,
            ...doc.data(),
          }));
          productList.sort((a, b) => a.id.localeCompare(b.id));
          setProducts(productList);
        } else {
          setProducts([]);
        }
      } catch (error) {
        console.error('Error fetching products:', error);
        setProducts([]);
      }
    };
    fetchProducts();
  }, [db]);

  return (
    <div className="admin-dashboard">
      <header>
        <h1>Admin Dashboard</h1>
      </header>
      <div className="dashboard-content">
        <div className="admin-actions">
          <button onClick={() => setShowUserList(!showUserList)} className="action-button">
            {showUserList ? 'Hide User List' : 'Show User List'}
          </button>
          <button onClick={() => setShowSupplierRequests(!showSupplierRequests)} className="action-button">
            {showSupplierRequests ? 'Hide Supplier Requests' : 'Show Supplier Requests'}
          </button>
          <button onClick={() => setShowProductForm(true)} className="action-button add-product-button">
            Add Product
          </button>
        </div>

        <div className="earnings-section">
          <div className="total-earnings-container">
            <h2>Total Earnings from Checkout</h2>
            <p>${totalCheckoutEarnings.toFixed(2)}</p>
          </div>

          <div className="checkout-earnings">
            <h2>Earnings by Checkout</h2>
            <table className="earnings-table">
              <thead>
                <tr>
                  <th>Checkout ID</th>
                  <th>Service Fee</th>
                  <th>Final Total</th>
                  <th>User ID</th>
                  <th>Product Names</th>
                </tr>
              </thead>
              <tbody>
                {checkoutEarnings.map((checkout) => (
                  <tr key={checkout.id}>
                    <td>{checkout.id}</td>
                    <td>${checkout.totalEarnings.toFixed(2)}</td>
                    <td>${checkout.finalTotal.toFixed(2)}</td>
                    <td>{checkout.userId}</td>
                    <td>{checkout.productNames}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {showUserList && (
          <div className="user-list">
            <h2>User List</h2>
            <table className="user-table">
              <thead>
                <tr>
                  <th>User Name</th>
                  <th>Email</th>
                  <th>Role</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.map((user) => (
                  <tr key={user.id}>
                    <td>{user.name}</td>
                    <td>{user.email}</td>
                    <td>{user.isSupplier ? 'Supplier' : 'Customer'}</td>
                    <td>
                      <button onClick={() => handleDeleteUser(user.id)} className="delete-button">Delete</button>
                      <button onClick={() => handleRoleChange(user.id, user.isSupplier ? 'Customer' : 'Supplier')} className="role-change-button">
                        {user.isSupplier ? 'Change to Customer' : 'Change to Supplier'}
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {showSupplierRequests && (
          <div className="supplier-requests">
            <h2>Supplier Requests</h2>
            {supplierRequests.length === 0 ? (
              <p>No supplier requests at the moment.</p>
            ) : (
              <table className="request-table">
                <thead>
                  <tr>
                    <th>User Name</th>
                    <th>Email</th>
                    <th>ID Proof</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {supplierRequests.map((request) => (
                    <tr key={request.id}>
                      <td>{request.userName}</td>
                      <td>{request.userEmail}</td>
                      <td>
                        <a href={request.idProofUrl} target="_blank" rel="noopener noreferrer">View ID Proof</a>
                      </td>
                      <td>
                        <button onClick={() => handleApproveSupplier(request.id)} className="approve-button">Approve</button>
                        <button onClick={() => handleDenySupplier(request.id)} className="deny-button">Deny</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}

        {showProductForm && (
          <form className="product-form" onSubmit={handleSubmit}>
            <h2>Add Product</h2>
            <label>
              Product Name:
              <input type="text" value={name} onChange={(e) => setName(e.target.value)} required />
            </label>
            <label>
              Description:
              <textarea value={description} onChange={(e) => setDescription(e.target.value)} required />
            </label>
            <label>
              Price per Day:
              <input type="number" value={pricePerDay} onChange={(e) => setPricePerDay(e.target.value)} required />
            </label>
            <label>
              Main Image:
              <input type="file" onChange={(e) => setMainImageFile(e.target.files[0])} required />
            </label>
            <label>
              Additional Images:
              <input type="file" multiple onChange={handleAdditionalImagesChange} />
            </label>
            <label>
              Category:
              <select value={category} onChange={(e) => setCategory(e.target.value)}>
                <option value="Clothing">Clothing</option>
                <option value="Footwear">Footwear</option>
                <option value="Gear">Gear</option>
                <option value="Accessories">Accessories</option>
              </select>
            </label>
            <label>
              Subcategory:
              <select value={subcategory} onChange={(e) => setSubcategory(e.target.value)}>
                {/* Update this list dynamically based on category */}
                {category === 'Clothing' && (
                  <>
                    <option value="Men's Clothing">Men's Clothing</option>
                    <option value="Women's Clothing">Women's Clothing</option>
                  </>
                )}
                {/* Add more subcategory options based on category */}
              </select>
            </label>
            <button type="submit" className="submit-button">Add Product</button>
            <button type="button" onClick={() => setShowProductForm(false)} className="cancel-button">Cancel</button>
          </form>
        )}

        <button onClick={() => setShowProductHistory(!showProductHistory)} className="toggle-button">
          {showProductHistory ? 'Hide Product History' : 'Show Product History'}
        </button>

        {showProductHistory && (
          <div className="product-history">
            <h2>Product History</h2>
            {products === null ? (
              <p>Loading product history...</p>
            ) : products.length > 0 ? (
              <table className="product-history-table">
                <thead>
                  <tr>
                    <th>Product Name</th>
                    <th>Category</th>
                    <th>Subcategory</th>
                    <th>Price per Day</th>
                  </tr>
                </thead>
                <tbody>
                  {products.map((product) => (
                    <tr key={product.id}>
                      <td>{product.name}</td>
                      <td>{product.category}</td>
                      <td>{product.subcategory}</td>
                      <td>${product.pricePerDay}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p>No product history available.</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
